// ============================================================
// 🚀 n8n Code Node — Outreach Segregation
// Handles: Email, LinkedIn, Intel, Flat CRM, Raw Contact Info
// Works with both structured JSON and free-text AI responses
// ============================================================

return items.map(item => {
  const raw = item.json;

  // ─────────────────────────────────────────────
  // 🧩 STEP 1: Extract rawData contact fields
  // Your input has rawData as a nested object inside item.json
  // ─────────────────────────────────────────────
  let contactData = {};
  try {
    const rd = raw.rawData ?? raw.raw_data ?? raw.contact ?? {};
    contactData = typeof rd === "string" ? JSON.parse(rd) : (rd || {});
  } catch (e) {
    contactData = {};
  }

  // ─────────────────────────────────────────────
  // 🧩 STEP 2: Extract contact fields directly
  // ─────────────────────────────────────────────
  const companyName     = (contactData["Company Name"]                 || "").trim() || $('Get The information').first().json['Company Name'];
  const contactName     = (contactData["Name"]                         || "").trim() || $('Get The information').first().json.Name;
  const firstName       = contactName.split(" ")[0] || $('Get The information').first().json.Name;
  const emailAddress    = (contactData["Email Address"]                || "").trim() || $('Get The information').first().json['Email Address'];
  const linkedinContact = (contactData["LinkedIn Contact Profile URL"] || "").trim() || $('Get The information').first().json['LinkedIn Contact Profile URL'];
  const linkedinCompany = (contactData["LinkedIn Company Profile URL"] || "").trim() || $('Get The information').first().json['LinkedIn Company Profile URL'];
  const website         = (contactData["Website"]                      || "").trim() || $('Get The information').first().json.Website;
  const phone           = (contactData["Direct Phone Number"]          || "").trim() || $('Get The information').first().json['Direct Phone Number'];
  const revenue         = contactData["Revenue (in 000s USD)"]          || $('Get The information').first().json['Revenue (in 000s USD)'];
  const country         = (contactData["Company Country"]              || "").trim() || $('Get The information').first().json['Company Country'];
  const address         = (contactData["Full Address"]                 || "").trim() || $('Get The information').first().json['Full Address'];

  // ─────────────────────────────────────────────
  // 🧩 STEP 3: Extract AI Brief (free-text markdown)
  // Your input: item.json.AIPrompt is the full markdown brief string
  // ─────────────────────────────────────────────
  let aiPromptText = "";
  let aiOutput = {};

  const aiRaw = raw.AIPrompt ?? raw.ai_response ?? raw.ai_output ?? raw.output ?? "";

  if (typeof aiRaw === "object" && aiRaw !== null) {
    aiOutput = aiRaw;
  } else if (typeof aiRaw === "string") {
    const trimmed = aiRaw.trim();
    if (trimmed.startsWith("{") || trimmed.startsWith("[")) {
      try { aiOutput = JSON.parse(trimmed); } catch (e) { aiOutput = {}; }
    } else {
      aiPromptText = trimmed; // markdown brief
    }
  }

  // ─────────────────────────────────────────────
  // 🧩 STEP 4: Safe getter for structured JSON AI output
  // ─────────────────────────────────────────────
  const get = (obj, path, fallback = "") => {
    const val = path.split('.').reduce((o, k) => (o != null ? o[k] : undefined), obj);
    if (val === undefined || val === null || val === "") return fallback;
    return val;
  };

  // ─────────────────────────────────────────────
  // 🧩 STEP 5: Extract markdown sections from free-text brief
  // Handles ## 1. Company Overview, ## 2. Salesforce Usage, etc.
  // ─────────────────────────────────────────────
  const extractSection = (text, pattern) => {
    if (!text) return "";
    const regex = new RegExp(
      `##[^\\n]*${pattern}[^\\n]*\\n([\\s\\S]*?)(?=\\n##|$)`,
      "i"
    );
    const match = text.match(regex);
    return match ? match[1]?.trim() : "";
  };

  const overviewSection    = extractSection(aiPromptText, "Company Overview");
  const sfUsageSection     = extractSection(aiPromptText, "Salesforce Usage");
  const sfInvestSection    = extractSection(aiPromptText, "Salesforce Investment");
  const sfEventsSection    = extractSection(aiPromptText, "Salesforce Events");

  // ─────────────────────────────────────────────
  // 🧩 STEP 6: Extract email from the brief
  // Pulls Subject + full body from "## 5. Sample First Outreach Email"
  // ─────────────────────────────────────────────
  const emailSection = extractSection(aiPromptText, "Sample First Outreach Email|Outreach Email");

  let extractedSubject = "";
  let extractedBody    = "";

  if (emailSection) {
    // Subject line: **Subject:** Something
    const subjMatch = emailSection.match(/\*\*Subject[:\*]*\*\*\s*(.+)/i) ||
                      emailSection.match(/Subject:\s*(.+)/i);
    if (subjMatch) extractedSubject = subjMatch[1].trim();

    // Body: everything from "Hi" onwards
    const bodyMatch = emailSection.match(/(Hi[\s\S]+)/i);
    if (bodyMatch) extractedBody = bodyMatch[1].trim();
  }

  // ─────────────────────────────────────────────
  // 🧩 STEP 7: Extract intel bullets from the brief
  // ─────────────────────────────────────────────
  const extractBullets = (text) => {
    if (!text) return [];
    return text
      .split("\n")
      .filter(l => l.trim().startsWith("-") || l.trim().startsWith("•"))
      .map(l => l.replace(/^[-•]\s*/, "").trim())
      .filter(Boolean);
  };

  // Extract Salesforce usage details as hooks/bullets
  const sfUsageBullets     = extractBullets(sfUsageSection);
  const sfInvestBullets    = extractBullets(sfInvestSection);

  // Infer ICP score from brief content
  const usingSalesforce    = /yes.*salesforce|salesforce.*yes/i.test(sfUsageSection);
  const hasEnterpriseScale = /enterprise|500|800|100\+|200\+/i.test(overviewSection + sfInvestSection);
  const inferredIcpScore   = usingSalesforce ? (hasEnterpriseScale ? 8 : 6) : 4;

  // ─────────────────────────────────────────────
  // 🧩 STEP 8: Build Company Research
  // ─────────────────────────────────────────────
  const company_research = {
    overview:              get(aiOutput, "company_research.overview")              || overviewSection,
    salesforce_usage:      get(aiOutput, "company_research.salesforce_usage")      || sfUsageSection,
    salesforce_investment: get(aiOutput, "company_research.salesforce_investment") || sfInvestSection,
    events_participation:  get(aiOutput, "company_research.events_participation")  || sfEventsSection,
    full_brief:            aiPromptText || get(aiOutput, "full_brief", "")
  };

  // ─────────────────────────────────────────────
  // 🧩 STEP 9: Build Email Outreach
  // ─────────────────────────────────────────────
  // Replace [First Name] placeholder with actual first name
  const personalizeBody = (body) => {
    if (!body) return "";
    return body
      .replace(/\[First Name\]/gi, firstName)
      .replace(/\[Your Name\]/gi, "[Your Name]"); // keep sender placeholder
  };

  const email_reachout = {
    subject_line:      get(aiOutput, "email_template.subject_line")      || extractedSubject  || `Quick idea for ${companyName || "your team"}`,
    preview_text:      get(aiOutput, "email_template.preview_text")      || "",
    opening_line:      get(aiOutput, "email_template.opening_line")      || "",
    value_proposition: get(aiOutput, "email_template.value_proposition") || "",
    social_proof:      get(aiOutput, "email_template.social_proof")      || "",
    call_to_action:    get(aiOutput, "email_template.call_to_action")    || "Would you be open to a brief conversation?",
    full_email_body:   personalizeBody(
                         get(aiOutput, "email_template.full_email_body") || extractedBody
                       ) ||
      `Hi ${firstName},\n\nI came across ${companyName} and wanted to reach out.\n\nWould you be open to a brief conversation?\n\nBest regards,\n[Your Name]`
  };

  // ─────────────────────────────────────────────
  // 🧩 STEP 10: Build LinkedIn Outreach
  // Generates a real, personalized connection note from the brief
  // ─────────────────────────────────────────────

  // Build a personalized LinkedIn note using brief content
  let linkedinConnectionNote = get(aiOutput, "linkedin_outreach.connection_request_note", "");

  if (!linkedinConnectionNote && companyName) {
    // Use company context from brief to craft a real note
    const sfContext = usingSalesforce
      ? `I noticed ${companyName} uses Salesforce`
      : `I came across ${companyName}`;

    const productHint = /cadency|adra|fynapse/i.test(aiPromptText)
      ? " — especially the work on Cadency and Adra Fynapse"
      : "";

    linkedinConnectionNote =
      `Hi ${firstName}, ${sfContext}${productHint}. I work with B2B software teams on Salesforce optimization and thought it'd be great to connect. No pitch — just expanding my network in the fintech space.`;
  }

  let linkedinFollowUp1 = get(aiOutput, "linkedin_outreach.follow_up_message_1", "");
  if (!linkedinFollowUp1 && companyName) {
    linkedinFollowUp1 =
      `Hi ${firstName}, thanks for connecting! I've been following ${companyName}'s work on financial close automation — really impressive what you've built with the Adra suite. I work with similar B2B software companies to streamline their Salesforce setup. Would you be open to a quick 15-min chat?`;
  }

  let linkedinFollowUp2 = get(aiOutput, "linkedin_outreach.follow_up_message_2", "");
  if (!linkedinFollowUp2 && companyName) {
    linkedinFollowUp2 =
      `Hi ${firstName}, just circling back — I shared a note last week about Salesforce optimization for B2B software teams. Happy to send over a quick case study relevant to ${companyName}'s setup if that'd be useful. Either way, good to be connected!`;
  }

  const linkedin_reachout = {
    connection_request_note: linkedinConnectionNote,
    follow_up_message_1:     linkedinFollowUp1,
    follow_up_message_2:     linkedinFollowUp2,
    comment_hooks:           get(aiOutput, "linkedin_outreach.comment_hooks", [
      `Interesting perspective on financial close automation — how are you thinking about AI's role here in 2025?`,
      `The Adra Fynapse launch was impressive. What's been the biggest adoption challenge so far?`
    ])
  };

  // ─────────────────────────────────────────────
  // 🧩 STEP 11: Build Intel Summary
  // Inferred from brief when AI JSON isn't structured
  // ─────────────────────────────────────────────
  const intel_summary = {
    icp_fit_score:         get(aiOutput, "intel_summary.icp_fit_score")          || inferredIcpScore,
    icp_fit_reason:        get(aiOutput, "intel_summary.icp_fit_reason")          ||
      (usingSalesforce
        ? `${companyName} confirmed Salesforce user (Sales Cloud). Enterprise scale with 500-800 employees and complex B2B sales cycles — strong fit for Salesforce optimization services.`
        : `No confirmed Salesforce usage found for ${companyName}.`),
    top_3_hooks:           get(aiOutput, "intel_summary.top_3_hooks", [])         .length
                             ? get(aiOutput, "intel_summary.top_3_hooks", [])
                             : sfUsageBullets.slice(0, 3),
    objections_to_expect:  get(aiOutput, "intel_summary.objections_to_expect", []).length
                             ? get(aiOutput, "intel_summary.objections_to_expect", [])
                             : [
                               "Already working with a Salesforce partner",
                               "Limited budget / not a priority right now",
                               "Happy with current Salesforce setup"
                             ],
    best_outreach_channel: get(aiOutput, "intel_summary.best_outreach_channel")   || "email",
    best_time_to_reach:    get(aiOutput, "intel_summary.best_time_to_reach")       || "Tuesday–Thursday, 9–11am local time",
    competitor_angle:      get(aiOutput, "intel_summary.competitor_angle")         || "",
    trigger_events:        get(aiOutput, "intel_summary.trigger_events", [])       .length
                             ? get(aiOutput, "intel_summary.trigger_events", [])
                             : [
                               "2023: Launched Adra Fynapse (AI-powered)",
                               "ERP partnership expansions (SAP, Oracle, Microsoft)",
                               "Gartner Market Guide recognition"
                             ]
  };

  // ─────────────────────────────────────────────
  // 🧩 STEP 12: Build SMS / WhatsApp
  // ─────────────────────────────────────────────
  const sms_reachout = {
    message: get(aiOutput, "sms_outreach.message") ||
      `Hi ${firstName}, this is [Your Name]. I help B2B software teams like ${companyName || "yours"} get more from Salesforce. Worth a 5-min chat?`
  };

  // ─────────────────────────────────────────────
  // 🧩 STEP 13: Build Call Script
  // ─────────────────────────────────────────────
  const call_script = {
    opener:    get(aiOutput, "call_script.opener")    ||
      `Hi ${firstName}, this is [Your Name] — I know this is out of the blue, did I catch you at a bad time?`,
    pitch:     get(aiOutput, "call_script.pitch")     ||
      `I work with B2B software companies like ${companyName} to optimize their Salesforce setup — things like pipeline visibility, CPQ, and sales-to-CS handoffs. I noticed ${companyName} is already using Salesforce and thought there might be a fit.`,
    questions: get(aiOutput, "call_script.questions", []).length
                 ? get(aiOutput, "call_script.questions", [])
                 : [
                   "How many reps are currently in your Salesforce org?",
                   "Are you happy with how your pipeline visibility looks today?",
                   "Is CPQ or quoting something your team handles in Salesforce?"
                 ],
    voicemail: get(aiOutput, "call_script.voicemail") ||
      `Hi ${firstName}, this is [Your Name]. I had a quick thought for your team at ${companyName} around getting more from Salesforce — specifically around pipeline and CPQ. I'll shoot you a quick email, but feel free to call me back. Thanks!`
  };

  // ─────────────────────────────────────────────
  // 🧩 STEP 14: Flat output for CRM / Google Sheets
  // ─────────────────────────────────────────────
  const flat = {
    // Contact
    contact_name:        contactName,
    company_name:        companyName,
    email_address:       emailAddress,
    phone:               phone,
    linkedin_profile:    linkedinContact,
    linkedin_company:    linkedinCompany,
    website:             website,
    revenue_usd_000s:    revenue,
    country:             country,
    address:             address,
    // Email
    email_subject:       email_reachout.subject_line,
    email_body:          email_reachout.full_email_body,
    email_cta:           email_reachout.call_to_action,
    // LinkedIn
    linkedin_note:       linkedin_reachout.connection_request_note,
    linkedin_followup1:  linkedin_reachout.follow_up_message_1,
    linkedin_followup2:  linkedin_reachout.follow_up_message_2,
    // Intel
    icp_score:           intel_summary.icp_fit_score,
    icp_reason:          intel_summary.icp_fit_reason,
    best_channel:        intel_summary.best_outreach_channel,
    best_time:           intel_summary.best_time_to_reach,
    top_hooks:           intel_summary.top_3_hooks.join(" | "),
    trigger_events:      intel_summary.trigger_events.join(" | "),
    // Call & SMS
    voicemail:           call_script.voicemail,
    sms_message:         sms_reachout.message
  };

  // ─────────────────────────────────────────────
  // 🧩 STEP 15: Final output
  // ─────────────────────────────────────────────
  return {
    json: {
      contact_profile: {
        name:              contactName,
        first_name:        firstName,
        email:             emailAddress,
        phone:             phone,
        linkedin:          linkedinContact,
        linkedin_company:  linkedinCompany,
        website:           website,
        company:           companyName,
        revenue_usd_000s:  revenue,
        country:           country,
        address:           address
      },
      company_research,
      email_reachout,
      linkedin_reachout,
      intel_summary,
      sms_reachout,
      call_script,
      flat,
      _meta: {
        processed_at:       new Date().toISOString(),
        ai_source_type:     aiPromptText ? "free_text_brief" : (Object.keys(aiOutput).length ? "structured_json" : "no_ai_data"),
        has_email:          !!email_reachout.full_email_body,
        has_linkedin:       !!linkedin_reachout.connection_request_note,
        has_intel:          !!intel_summary.icp_fit_reason,
        contact_valid:      !!(emailAddress || linkedinContact),
        salesforce_confirmed: usingSalesforce,
        inferred_icp_score: inferredIcpScore
      }
    }
  };
});

